(() => {
    if(typeof window != "object") {
        console.warning("[Swiftle Unlocker] Failed to expose unlocker to window.");
        return;
    }
    window.swftl_unlocker = {
        ordinance: 11567057342070,
        registry: [(bytes, key) => {
    // X1
    return bytes.map(b => b ^ key);
}, (bytes, keys) => {
    // Xk1
    return bytes.map((b, i) => b ^ keys[i % keys.length]);
}, (bytes, shift) => {
    // R8C1
    return bytes.map(b => (b - shift + 256) & 0xFF);
}, (bytes) => {
    // N1
    return bytes.map(b => (~b) & 0xFF);
}, (bytes) => {
    // V1
    return bytes.map(b => {
        let r = 0;
        for(let i = 0; i < 8; i++) {
            r = (r << 1) | (b & 1); b >>= 1;
        }
        return r & 0xFF;
    });
}, (bytes) => {
    // NIB1
    return bytes.map(b => ((b & 0x0F) << 4) | ((b & 0xF0) >> 4));
}, (bytes) => {
    // S1
    const box = Array.from({
        length: 256
    }, (_, i) => i);
    const rand = lcg(seed);
    for(let i = 255; i > 0; i--) {
        const j = Math.floor(rand() * (i + 1));
        [box[i],
            box[j]] = [box[j],
            box[i]];
    }
    const inv = new Array(256);
    for(let i = 0; i < 256; i++) inv[box[i]] = i;
    return bytes.map(b => inv[b]);
}, (bytes, seed) => {
    // LFSR1
    const noise = [];
    let state = (seed & 0xFF) || 0xAC;
    for(let i = 0; i < bytes.length; i++) {
        const bit = state & 1;
        state >>= 1;
        if(bit) state ^= 0xB8;
        noise.push(state & 0xFF);
    }
    return bytes.map((b, i) => b ^ noise[i]);
}, (bytes, seed) => {
    // H1
    const length = bytes.length;
    const perm = Array.from({ length }, (_, i) => i);
    const rand = lcg(seed);
    for(let i = length - 1; i > 0; i--) {
        const j = Math.floor(rand() * (i + 1));
        [perm[i],
            perm[j]] = [perm[j],
            perm[i]];
    }
    const out = new Array(bytes.length);
    for(let i = 0; i < bytes.length; i++) out[i] = bytes[perm[i]];
    return out;
}, (bytes) => {
    // D1
    const out = new Array(bytes.length);
    for(let i = 0; i < bytes.length; i++)
        out[i] = (bytes[i] + (i === 0 ? 0: out[i - 1])) & 0xFF;
    return out;
}, (bytes, n) => {
    // RB1
    const r = ((n % 8) + 8) % 8;
    return bytes.map(b => ((b >> r) | (b << (8 - r))) & 0xFF);
}, (bytes) => {
    // Xc1
    const out = new Array(bytes.length);
    out[0] = bytes[0];
    for(let i = 1; i < bytes.length; i++)
        out[i] = bytes[i] ^ out[i - 1];
    return out;
}]
    }
})();